// Vapi's "Custom LLM" posts an OpenAI-shaped chat request:
//   { model, messages: [{role, content}, ...], ... }
// We pull out the caller's latest turn plus the transcript so far, and hand both
// to the AI Agent. Vapi keeps the conversation state - n8n stays stateless.
const body = $input.first().json.body || {};
const messages = Array.isArray(body.messages) ? body.messages : [];

let userMessage = '';
for (let i = messages.length - 1; i >= 0; i--) {
  if (messages[i].role === 'user') {
    userMessage = typeof messages[i].content === 'string'
      ? messages[i].content
      : JSON.stringify(messages[i].content);
    break;
  }
}

const priorTurns = messages
  .filter((m) => m.role === 'user' || m.role === 'assistant')
  .slice(0, -1)
  .map((m) => m.role + ': ' + (typeof m.content === 'string' ? m.content : JSON.stringify(m.content)))
  .join('\n');

return [{
  json: {
    userMessage: userMessage || 'Hello',
    transcript: priorTurns || '(no prior conversation)',
    model: body.model || 'gpt-4o',
  },
}];

// Vapi expects an OpenAI chat-completion object back. Anything else and the
// assistant goes silent mid-call, which is the classic failure of this lab.
const answer = $input.first().json.output || '';
const model = $('Prepare Prompt').first().json.model || 'gpt-4o';

return [{
  json: {
    id: 'chatcmpl-' + $execution.id,
    object: 'chat.completion',
    created: Math.floor(Date.now() / 1000),
    model: model,
    choices: [
      {
        index: 0,
        message: { role: 'assistant', content: answer },
        finish_reason: 'stop',
      },
    ],
  },
}];
